//! SQLite connection setup, migrations, and the `effective_weight` SQL function.

use rusqlite::functions::FunctionFlags;
use rusqlite::{Connection, ErrorCode};
use std::time::{Duration, Instant};

use crate::error::Result;

const SCHEMA: &str = include_str!("schema.sql");
const WAL_RETRY_DELAY: Duration = Duration::from_millis(25);
const WAL_RETRY_TIMEOUT: Duration = Duration::from_secs(5);

/// Open (or create) a MindLeak database at `path`, apply the schema, and register
/// the `effective_weight` scalar SQL function used by graph queries.
pub fn open(path: &str) -> Result<Connection> {
    let conn = Connection::open(path)?;
    configure(&conn)?;
    Ok(conn)
}

/// Open an in-memory database (used by tests and ephemeral tooling).
pub fn open_in_memory() -> Result<Connection> {
    let conn = Connection::open_in_memory()?;
    configure(&conn)?;
    Ok(conn)
}

fn configure(conn: &Connection) -> Result<()> {
    conn.pragma_update(None, "busy_timeout", 5000)?;
    enable_wal(conn)?;
    conn.pragma_update(None, "foreign_keys", "ON")?;
    conn.execute_batch(SCHEMA)?;
    migrate(conn)?;
    register_functions(conn)?;
    Ok(())
}

fn enable_wal(conn: &Connection) -> Result<()> {
    let deadline = Instant::now() + WAL_RETRY_TIMEOUT;
    loop {
        match conn.pragma_update(None, "journal_mode", "WAL") {
            Ok(()) => return Ok(()),
            Err(error) if is_busy(&error) && Instant::now() < deadline => {
                std::thread::sleep(WAL_RETRY_DELAY);
            }
            Err(error) => return Err(error.into()),
        }
    }
}

fn is_busy(error: &rusqlite::Error) -> bool {
    matches!(
        error,
        rusqlite::Error::SqliteFailure(code, _)
            if matches!(code.code, ErrorCode::DatabaseBusy | ErrorCode::DatabaseLocked)
    )
}

/// Register `effective_weight(base, half_life_hours, updated_at, now)` so the
/// decay formula can run inside SQL (filtering/ordering) without SQLite math
/// extensions.
fn register_functions(conn: &Connection) -> Result<()> {
    conn.create_scalar_function(
        "effective_weight",
        4,
        FunctionFlags::SQLITE_UTF8 | FunctionFlags::SQLITE_DETERMINISTIC,
        |ctx| {
            let base: f64 = ctx.get(0)?;
            let half_life: f64 = ctx.get(1)?;
            let updated_at: i64 = ctx.get(2)?;
            let now: i64 = ctx.get(3)?;
            Ok(crate::decay::effective_weight(
                base, half_life, updated_at, now,
            ))
        },
    )?;
    Ok(())
}

/// Idempotently add columns to a pre-existing `edges` table (fresh databases
/// already have them from the schema). Backfills signal span and unambiguous
/// structural ownership without trying to infer artifact paths from symbol ids.
fn migrate(conn: &Connection) -> Result<()> {
    conn.execute_batch("BEGIN IMMEDIATE")?;
    let result = migrate_locked(conn);
    match result {
        Ok(()) => conn.execute_batch("COMMIT")?,
        Err(error) => {
            let _ = conn.execute_batch("ROLLBACK");
            return Err(error);
        }
    }
    Ok(())
}

fn migrate_locked(conn: &Connection) -> Result<()> {
    if !column_exists(conn, "edges", "first_seen")? {
        conn.execute(
            "ALTER TABLE edges ADD COLUMN first_seen INTEGER NOT NULL DEFAULT 0",
            [],
        )?;
    }
    conn.execute(
        "UPDATE edges SET first_seen = updated_at WHERE first_seen = 0",
        [],
    )?;
    if !column_exists(conn, "edges", "reinforcement_count")? {
        conn.execute(
            "ALTER TABLE edges ADD COLUMN reinforcement_count INTEGER NOT NULL DEFAULT 1",
            [],
        )?;
    }
    if !column_exists(conn, "edges", "owner_id")? {
        conn.execute("ALTER TABLE edges ADD COLUMN owner_id TEXT", [])?;
    }
    conn.execute(
        "UPDATE edges
         SET owner_id = source_id
         WHERE owner_id IS NULL AND relation = 'contains'",
        [],
    )?;
    conn.execute(
        "CREATE INDEX IF NOT EXISTS idx_edges_owner ON edges(owner_id)",
        [],
    )?;
    Ok(())
}

fn column_exists(conn: &Connection, table: &str, column: &str) -> Result<bool> {
    let mut stmt = conn.prepare(&format!("PRAGMA table_info({table})"))?;
    let mut rows = stmt.query([])?;
    while let Some(row) = rows.next()? {
        let name: String = row.get(1)?;
        if name == column {
            return Ok(true);
        }
    }
    Ok(false)
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::{Arc, Barrier};
    use std::time::{SystemTime, UNIX_EPOCH};

    fn temp_db(tag: &str) -> String {
        let nanos = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|duration| duration.as_nanos())
            .unwrap_or(0);
        let mut path = std::env::temp_dir();
        path.push(format!("mindleak-{tag}-{}-{nanos}.db", std::process::id()));
        path.to_string_lossy().into_owned()
    }

    fn cleanup(path: &str) {
        let _ = std::fs::remove_file(path);
        let _ = std::fs::remove_file(format!("{path}-wal"));
        let _ = std::fs::remove_file(format!("{path}-shm"));
    }

    fn create_legacy_database(path: &str) {
        let connection = Connection::open(path).unwrap();
        connection
            .execute_batch(
                "CREATE TABLE nodes (
                     id TEXT PRIMARY KEY,
                     type TEXT NOT NULL,
                     label TEXT NOT NULL,
                     content TEXT,
                     created_at INTEGER NOT NULL,
                     last_accessed_at INTEGER NOT NULL
                 );
                 CREATE TABLE edges (
                     source_id TEXT NOT NULL,
                     target_id TEXT NOT NULL,
                     relation TEXT NOT NULL,
                     weight REAL NOT NULL DEFAULT 1.0,
                     half_life_hours REAL NOT NULL DEFAULT 48.0,
                     updated_at INTEGER NOT NULL,
                     first_seen INTEGER NOT NULL DEFAULT 0,
                     PRIMARY KEY (source_id, target_id, relation)
                 );
                 INSERT INTO nodes VALUES
                     ('artifact:a', 'artifact', 'a', NULL, 10, 10),
                     ('symbol:a:f', 'symbol', 'f', NULL, 10, 10);
                 INSERT INTO edges VALUES
                     ('artifact:a', 'symbol:a:f', 'contains', 1.0, 168.0, 10, 0);",
            )
            .unwrap();
    }

    #[test]
    fn migrate_adds_edge_evidence_columns_and_backfills_contains_owner() {
        // Regression: an existing graph lacks columns from newer ADRs; normal
        // open must upgrade it in place and preserve its structural facts.
        let connection = Connection::open_in_memory().unwrap();
        connection
            .execute_batch(
                "CREATE TABLE nodes (
                     id TEXT PRIMARY KEY,
                     type TEXT NOT NULL,
                     label TEXT NOT NULL,
                     content TEXT,
                     created_at INTEGER NOT NULL,
                     last_accessed_at INTEGER NOT NULL
                 );
                 CREATE TABLE edges (
                     source_id TEXT NOT NULL,
                     target_id TEXT NOT NULL,
                     relation TEXT NOT NULL,
                     weight REAL NOT NULL DEFAULT 1.0,
                     half_life_hours REAL NOT NULL DEFAULT 48.0,
                     updated_at INTEGER NOT NULL,
                     PRIMARY KEY (source_id, target_id, relation)
                 );
                 INSERT INTO nodes VALUES
                     ('artifact:a', 'artifact', 'a', NULL, 10, 10),
                     ('symbol:a:f', 'symbol', 'f', NULL, 10, 10);
                 INSERT INTO edges VALUES
                     ('artifact:a', 'symbol:a:f', 'contains', 1.0, 168.0, 10);",
            )
            .unwrap();

        configure(&connection).unwrap();

        for column in ["first_seen", "reinforcement_count", "owner_id"] {
            assert!(column_exists(&connection, "edges", column).unwrap());
        }
        let (first_seen, reinforcement_count, owner_id): (i64, i64, Option<String>) = connection
            .query_row(
                "SELECT first_seen, reinforcement_count, owner_id FROM edges",
                [],
                |row| Ok((row.get(0)?, row.get(1)?, row.get(2)?)),
            )
            .unwrap();
        assert_eq!(first_seen, 10);
        assert_eq!(reinforcement_count, 1);
        assert_eq!(owner_id.as_deref(), Some("artifact:a"));
    }

    #[test]
    fn concurrent_opens_serialize_legacy_migration() {
        let path = temp_db("concurrent-migration");
        create_legacy_database(&path);
        let barrier = Arc::new(Barrier::new(3));
        let mut handles = Vec::new();
        for _ in 0..2 {
            let path = path.clone();
            let barrier = Arc::clone(&barrier);
            handles.push(std::thread::spawn(move || {
                barrier.wait();
                open(&path)
            }));
        }
        barrier.wait();

        for handle in handles {
            let result = handle.join().unwrap();
            assert!(result.is_ok(), "concurrent open failed: {result:?}");
        }
        let connection = open(&path).unwrap();
        let (first_seen, owner_id): (i64, Option<String>) = connection
            .query_row("SELECT first_seen, owner_id FROM edges", [], |row| {
                Ok((row.get(0)?, row.get(1)?))
            })
            .unwrap();
        assert_eq!(first_seen, 10);
        assert_eq!(owner_id.as_deref(), Some("artifact:a"));
        drop(connection);
        cleanup(&path);
    }

    #[test]
    fn held_lock_does_not_multiply_wal_retry_timeout() {
        let path = temp_db("bounded-wal-retry");
        create_legacy_database(&path);
        let holder = Connection::open(&path).unwrap();
        holder.execute_batch("BEGIN EXCLUSIVE").unwrap();

        let started = Instant::now();
        let result = open(&path);
        let elapsed = started.elapsed();

        assert!(result.is_err());
        assert!(
            elapsed < Duration::from_secs(12),
            "open exceeded bounded retry window: {elapsed:?}"
        );
        holder.execute_batch("ROLLBACK").unwrap();
        cleanup(&path);
    }
}
